async function transform(input, context) {
  const userIds = input.userIds || [1, 2, 3];
  console.log(`Will fetch ${userIds.length} users in parallel (max ${context.vars.maxConcurrency} concurrent)`);

  return {
    userIds: userIds,
    apiUrl: context.vars.apiBaseUrl
  };
}

async function transform(input, context) {
  const loopResults = context.steps['fetch-users']?.results || [];

  // Parse all user data
  const users = loopResults
    .map(r => {
      try {
        return JSON.parse(r.logs || '{}');
      } catch {
        return null;
      }
    })
    .filter(Boolean);

  console.log(`Successfully fetched ${users.length} users`);

  return {
    count: users.length,
    users: users.map(u => ({
      id: u.id,
      name: u.name,
      email: u.email,
      company: u.company?.name
    }))
  };
}
